m03-views-composition/composing-complex-.prompt:
Este body está longo. Identifique o melhor candidato para extração e mostre como fazer:

struct TarefaView: View {
    let tarefa: Tarefa
    @State private var expandida = false

    var body: some View {
        VStack(alignment: .leading) {
            HStack {
                Image(systemName: tarefa.concluida ? "checkmark.circle.fill" : "circle")
                    .foregroundStyle(tarefa.concluida ? .green : .gray)
                Text(tarefa.titulo).font(.headline)
                Spacer()
            }
            if expandida {
                Text(tarefa.notas ?? "Sem notas")
