                .foregroundStyle(tarefa.concluida ? .green : .gray)
            Text(tarefa.titulo).font(.headline)
            Spacer()
        }
    }

    private var notas: some View {
        Text(tarefa.notas ?? "Sem notas")
            .font(.body)
            .foregroundStyle(.secondary)
            .padding(.top, 4)
    }

    var body: some View {
        VStack(alignment: .leading) {
            cabecalho
            if expandida { notas }
        }
        .onTapGesture { expandida.toggle() }
    }
}

