    func carregar(id: UUID) {
        Task {
            // await libera a main thread durante a busca
            perfil = try? await APIService.buscar(id: id)
            // retoma na main thread — seguro!
        }
    }
}

Solução 2 — @Observable (moderno, sem @Published):
@MainActor
