m10-combine/combine-fundamentals.solution:
init() {
    $textoBusca
        .debounce(for: .milliseconds(300), scheduler: RunLoop.main)
        .removeDuplicates()
        .sink { [weak self] texto in
            guard let self else { return }
            Task {
                await self.buscar(query: texto)
            }
        }
        .store(in: &cancelaveis)  // guarda o token!
}

private func buscar(query: String) async {
    resultados = await BuscaService.buscar(query: query)
}

Observe: [weak self] evita retain cycle, .store(in: &cancelaveis) mantém o subscription vivo.

